    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTicker
        //
        // {
        //     "symbol": "BTC_USDC",
        //     "priceChange": "0",
        //     "priceChangePercent": "0",
        //     "weightedAvgPrice": "0",
        //     "lastPrice": "2.00",
        //     "lastQty": "10.000",
        //     "bestBidPrice": "1646.00",
        //     "bestBidQty": "10.000",
        //     "bestAskPrice": "1646.00",
        //     "bestAskQty": "10.000",
        //     "openPrice": "0.00",
        //     "highPrice": "0.00",
        //     "lowPrice": "0.00",
        //     "volume": "0.000",
        //     "quoteVolume": "0.00",
        //     "openTime": 1700142658697,
        //     "closeTime": 1700142658697,
        //     "openInterestBase": "1.000",
        //     "openInterestQuote": "0.43112300"
        // }
        //
        // fetchTickers
        //
        //     "ETH_USDC": {
        //       "priceChange": "0",
        //       "priceChangePercent": "0",
        //       "openPrice": "1646.15",
        //       "highPrice": "1646.15",
        //       "lowPrice": "1646.15",
        //       "lastPrice": "1646.15",
        //       "quoteVolume": "13.17",
        //       "volume": "0.008",
        //       "markPrice": "1645.15"
        //     }
        //
        // fetchMarkPrice
        //
        // {
        //     "markPrice": "100.00",
        //     "indexPrice": "100.00",
        //     "ltp": "101.34",
        //     "movingFundingRate": "0.08",
        //     "payoutFundingRate": "-0.03",
        //     "nextFundingPayout": 1711555532146
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        if (Helpers.isTrue(!Helpers.isEqual(marketId, null)))
        {
            market = this.market(marketId);
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object open = this.safeString(ticker, "openPrice");
        Object high = this.safeString(ticker, "highPrice");
        Object low = this.safeString(ticker, "lowPrice");
        Object close = this.safeString(ticker, "lastPrice");
        Object quoteVolume = this.safeString(ticker, "quoteVolume");
        Object baseVolume = this.safeString(ticker, "volume");
        Object percentage = this.safeString(ticker, "priceChangePercent");
        Object change = this.safeString(ticker, "priceChange");
        Object ts = this.safeInteger(ticker, "closeTime");
        if (Helpers.isTrue(Helpers.isEqual(ts, 0)))
        {
            ts = null;
        }
        Object datetime = this.iso8601(ts);
        Object bid = this.safeString(ticker, "bestBidPrice");
        Object bidVolume = this.safeString(ticker, "bestBidQty");
        Object ask = this.safeString(ticker, "bestAskPrice");
        Object askVolume = this.safeString(ticker, "bestAskQty");
        final Object finalTs = ts;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", finalTs );
            put( "datetime", datetime );
            put( "high", high );
            put( "low", low );
            put( "bid", bid );
            put( "bidVolume", bidVolume );
            put( "ask", ask );
            put( "askVolume", askVolume );
            put( "vwap", null );
            put( "open", open );
            put( "close", close );
            put( "last", null );
            put( "previousClose", null );
            put( "change", change );
            put( "percentage", percentage );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "markPrice", Defx.this.safeString(ticker, "markPrice") );
            put( "indexPrice", Defx.this.safeString(ticker, "indexPrice") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name defx#fetchOHLCV
     * @see https://api-docs.defx.com/#54b71951-1472-4670-b5af-4c2dc41e73d0
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] max=1000, max=100 when since is defined and is less than (now - (999 * (timeframe in ms)))
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch orders for
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object maxLimit = 1000;
            if (Helpers.isTrue(Helpers.isEqual(limit, null)))
            {
                limit = maxLimit;
            }
            limit = Helpers.mathMin(maxLimit, limit);
            final Object finalLimit = limit;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "interval", Defx.this.safeString(Defx.this.timeframes, timeframe, timeframe) );
                put( "limit", finalLimit );
            }};
            Object until = this.safeInteger2(parameters, "until", "till");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("until", "till")));
            Helpers.addElementToObject(request, "endTime", ((Helpers.isTrue((Helpers.isEqual(until, null))))) ? this.milliseconds() : until);
            if (Helpers.isTrue(Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTime", 0);
            } else
            {
                Helpers.addElementToObject(request, "startTime", since);
                if (Helpers.isTrue(Helpers.isEqual(until, null)))
                {
                    Object timeframeInSeconds = this.parseTimeframe(timeframe);
                    Object timeframeInMilliseconds = Helpers.multiply(timeframeInSeconds, 1000);
                    Object totalTimeframeInMilliseconds = Helpers.multiply(limit, timeframeInMilliseconds);
                    Helpers.addElementToObject(request, "endTime", this.sum(since, totalTimeframeInMilliseconds));
                }
            }
            Object response = (this.v1PublicGetSymbolsSymbolOhlc(this.extend(request, parameters))).join();
            //
            // [
            //     {
            //       "symbol": "BTC_USDC",
            //       "open": "0.00",
            //       "high": "0.00",
            //       "low": "0.00",
            //       "close": "0.00",
            //       "volume": "0.000",
            //       "quoteAssetVolume": "0.00",
            //       "takerBuyAssetVolume": "0.000",
            //       "takerBuyQuoteAssetVolume": "0.00",
            //       "numberOfTrades": 0,
            //       "start": 1702453663894,
            //       "end": 1702453663894,
            //       "isClosed": true
            //     }
            // ]
            //
            return this.parseOHLCVs(response, market, timeframe, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        // example response in fetchOHLCV
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, "start"), this.safeNumber(ohlcv, "open"), this.safeNumber(ohlcv, "high"), this.safeNumber(ohlcv, "low"), this.safeNumber(ohlcv, "close"), this.safeNumber(ohlcv, "volume")));
    }

