    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        // {
        //     "markPrice": "100.00",
        //     "indexPrice": "100.00",
        //     "ltp": "101.34",
        //     "movingFundingRate": "0.08",
        //     "payoutFundingRate": "-0.03",
        //     "nextFundingPayout": 1711555532146
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object markPrice = this.safeNumber(contract, "markPrice");
        Object indexPrice = this.safeNumber(contract, "indexPrice");
        Object fundingRateRaw = this.safeString(contract, "payoutFundingRate");
        Object fundingRate = Precise.stringDiv(fundingRateRaw, "100");
        Object fundingTime = this.safeInteger(contract, "nextFundingPayout");
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", Helpers.GetValue(market, "symbol") );
            put( "markPrice", markPrice );
            put( "indexPrice", indexPrice );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", Defx.this.parseNumber(fundingRate) );
            put( "fundingTimestamp", fundingTime );
            put( "fundingDatetime", Defx.this.iso8601(fundingTime) );
            put( "nextFundingRate", null );
            put( "nextFundingTimestamp", null );
            put( "nextFundingDatetime", null );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", null );
        }};
    }

