    public Object parseBalance(Object balances)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", balances );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balance = Helpers.GetValue(balances, i);
            Object code = this.safeCurrencyCode(this.safeString(balance, "asset"));
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(balance, "balance"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

    /**
     * @method
     * @name defx#createOrder
     * @description create a trade order
     * @see https://api-docs.defx.com/#ba222d88-8856-4d3c-87a9-7cec07bb2622
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.triggerPrice] The price a trigger order is triggered at
     * @param {string} [params.reduceOnly] for swap and future reduceOnly is a string 'true' or 'false' that cant be sent with close position set to true or in hedge mode. For spot margin and option reduceOnly is a boolean.
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object reduceOnly = this.safeBool2(parameters, "reduceOnly", "reduce_only");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("reduceOnly", "reduce_only")));
            Object orderType = ((String)type).toUpperCase();
            Object orderSide = ((String)side).toUpperCase();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "side", orderSide );
                put( "type", orderType );
            }};
            Object takeProfitPrice = this.safeString(parameters, "takeProfitPrice");
            Object triggerPrice = this.safeString2(parameters, "stopPrice", "triggerPrice");
            Object isMarket = Helpers.isEqual(orderType, "MARKET");
            Object isLimit = Helpers.isEqual(orderType, "LIMIT");
            Object timeInForce = this.safeStringUpper(parameters, "timeInForce");
            if (Helpers.isTrue(!Helpers.isEqual(timeInForce, null)))
            {
                // GTC, IOC, FOK, AON
                Helpers.addElementToObject(request, "timeInForce", timeInForce);
            } else
            {
                if (Helpers.isTrue(isLimit))
                {
                    Helpers.addElementToObject(request, "timeInForce", "GTC");
                }
            }
            if (Helpers.isTrue(reduceOnly))
            {
                Helpers.addElementToObject(request, "reduceOnly", reduceOnly);
            }
            Object clientOrderId = this.safeString(parameters, "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "newClientOrderId", clientOrderId);
            }
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)) || Helpers.isTrue(!Helpers.isEqual(takeProfitPrice, null))))
            {
                Helpers.addElementToObject(request, "workingType", "MARK_PRICE");
                if (Helpers.isTrue(!Helpers.isEqual(takeProfitPrice, null)))
                {
                    Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, takeProfitPrice));
                    if (Helpers.isTrue(isMarket))
                    {
                        Helpers.addElementToObject(request, "type", "TAKE_PROFIT_MARKET");
                    } else
                    {
                        Helpers.addElementToObject(request, "type", "TAKE_PROFIT_LIMIT");
                    }
                } else
                {
                    Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, triggerPrice));
                    if (Helpers.isTrue(isMarket))
                    {
                        Helpers.addElementToObject(request, "type", "STOP_MARKET");
                    } else
                    {
                        Helpers.addElementToObject(request, "type", "STOP_LIMIT");
                    }
                }
            }
            if (Helpers.isTrue(Helpers.isTrue(isLimit) && Helpers.isTrue(!Helpers.isEqual(price, null))))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            Helpers.addElementToObject(request, "quantity", this.amountToPrecision(symbol, amount));
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clOrdID", "clientOrderId", "client_order_id", "postOnly", "timeInForce", "stopPrice", "triggerPrice", "takeProfitPrice")));
            Object response = (this.v1PrivatePostApiOrder(this.extend(request, parameters))).join();
            //
            // {
            //     "success": true,
            //     "data": {
            //       "orderId": "",
            //       "clientOrderId": "",
            //       "cumulativeQty": "",
            //       "cumulativeQuote": "",
            //       "executedQty": "",
            //       "avgPrice": "",
            //       "origQty": "",
            //       "price": "",
            //       "reduceOnly": true,
            //       "side": "",
            //       "status": "",
            //       "symbol": "",
            //       "timeInForce": "",
            //       "type": "",
            //       "workingType": ""
            //     }
            // }
            //
            Object data = this.safeDict(response, "data");
            return this.parseOrder(data, market);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseOrderStatus(Object status)
    {
        if (Helpers.isTrue(!Helpers.isEqual(status, null)))
        {
            Object statuses = new java.util.HashMap<String, Object>() {{
                put( "NEW", "open" );
                put( "OPEN", "open" );
                put( "CANCELLED", "canceled" );
                put( "REJECTED", "rejected" );
                put( "FILLED", "closed" );
            }};
            return this.safeString(statuses, status, status);
        }
        return status;
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // {
        //     "orderId": "746472647227344528",
        //     "createdAt": "2024-10-25T16:49:31.077Z",
        //     "updatedAt": "2024-10-25T16:49:31.378Z",
        //     "clientOrderId": "0192c495-49c3-71ee-b3d3-7442a2090807",
        //     "reduceOnly": false,
        //     "side": "SELL",
        //     "status": "FILLED",
        //     "symbol": "SOL_USDC",
        //     "timeInForce": "GTC",
        //     "type": "MARKET",
        //     "origQty": "0.80",
        //     "executedQty": "0.80",
        //     "cumulativeQuote": "137.87440000",
        //     "avgPrice": "172.34300000",
        //     "totalPnL": "0.00000000",
        //     "totalFee": "0.07583092",
        //     "workingType": null,
        //     "postOnly": false,
        //     "linkedOrderParentType": null,
        //     "isTriggered": false,
        //     "slippagePercentage": "5"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object orderId = this.safeString(order, "orderId");
        Object clientOrderId = this.safeString(order, "clientOrderId");
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "origQty");
        Object orderType = this.safeStringLower(order, "type");
        Object status = this.safeString(order, "status");
        Object side = this.safeStringLower(order, "side");
        Object filled = this.omitZero(this.safeString(order, "executedQty"));
        Object average = this.omitZero(this.safeString(order, "avgPrice"));
        Object timeInForce = this.safeStringLower(order, "timeInForce");
        Object takeProfitPrice = null;
        Object triggerPrice = null;
        if (Helpers.isTrue(!Helpers.isEqual(orderType, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(orderType, "take_profit"), 0)))
            {
                takeProfitPrice = this.safeString(order, "stopPrice");
            } else
            {
                triggerPrice = this.safeString(order, "stopPrice");
            }
        }
        Object timestamp = this.parse8601(this.safeString(order, "createdAt"));
        Object lastTradeTimestamp = this.parse8601(this.safeString(order, "updatedAt"));
        final Object finalOrderType = orderType;
        final Object finalTriggerPrice = triggerPrice;
        final Object finalTakeProfitPrice = takeProfitPrice;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", Defx.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", lastTradeTimestamp );
            put( "lastUpdateTimestamp", lastTradeTimestamp );
            put( "status", Defx.this.parseOrderStatus(status) );
            put( "symbol", symbol );
            put( "type", finalOrderType );
            put( "timeInForce", timeInForce );
            put( "postOnly", Defx.this.safeBool(order, "postOnly") );
            put( "reduceOnly", Defx.this.safeBool(order, "reduceOnly") );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", finalTriggerPrice );
            put( "takeProfitPrice", finalTakeProfitPrice );
            put( "stopLossPrice", null );
            put( "average", average );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "cost", null );
            put( "trades", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", Defx.this.safeString(order, "totalFee") );
                put( "currency", "USDC" );
            }} );
            put( "info", order );
        }}, market);
    }

    /**
     * @method
     * @name defx#cancelOrder
     * @see https://api-docs.defx.com/#09186f23-f8d1-4993-acf4-9974d8a6ddb0
     * @description cancels an open order
     * @param {string} id order id
     * @param {string} symbol unified symbol of the market the order was made in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} An [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "orderId", id );
                put( "idType", "orderId" );
            }};
            Object clientOrderId = this.safeStringN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clOrdID", "clientOrderId", "client_order_id")));
            Object isByClientOrder = !Helpers.isEqual(clientOrderId, null);
            if (Helpers.isTrue(isByClientOrder))
            {
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrder() requires a symbol argument")) ;
                }
                Object market = this.market(symbol);
                Helpers.addElementToObject(request, "orderId", clientOrderId);
                Helpers.addElementToObject(request, "idType", "clientOrderId");
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clOrdID", "clientOrderId", "client_order_id")));
            Object response = (this.v1PrivateDeleteApiOrderOrderId(this.extend(request, parameters))).join();
            //
            // {
            //     "success": true
            // }
            //
            final Object finalSymbol = symbol;
            Object extendParams = new java.util.HashMap<String, Object>() {{
                put( "symbol", finalSymbol );
            }};
            if (Helpers.isTrue(isByClientOrder))
            {
                Helpers.addElementToObject(extendParams, "clientOrderId", clientOrderId);
            } else
            {
                Helpers.addElementToObject(extendParams, "id", id);
            }
            return this.extend(this.parseOrder(response), extendParams);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

