    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // {
        //     "positionId": "0192c495-4a68-70ee-9081-9d368bd16dfc",
        //     "symbol": "SOL_USDC",
        //     "positionSide": "SHORT",
        //     "entryPrice": "172.34300000",
        //     "quantity": "0.80",
        //     "marginAmount": "20.11561173",
        //     "marginAsset": "USDC",
        //     "pnl": "0.00000000"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market);
        Object size = Precise.stringAbs(this.safeString(position, "quantity"));
        Object side = this.safeStringLower(position, "positionSide");
        Object unrealisedPnl = this.omitZero(this.safeString(position, "pnl"));
        Object entryPrice = this.omitZero(this.safeString(position, "entryPrice"));
        Object initialMargin = this.safeString(position, "marginAmount");
        final Object finalMarket = market;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", Defx.this.safeString(position, "positionId") );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "timestamp", null );
            put( "datetime", null );
            put( "lastUpdateTimestamp", null );
            put( "initialMargin", Defx.this.parseNumber(initialMargin) );
            put( "initialMarginPercentage", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "entryPrice", Defx.this.parseNumber(entryPrice) );
            put( "notional", null );
            put( "leverage", null );
            put( "unrealizedPnl", Defx.this.parseNumber(unrealisedPnl) );
            put( "realizedPnl", null );
            put( "contracts", Defx.this.parseNumber(size) );
            put( "contractSize", Defx.this.safeNumber(finalMarket, "contractSize") );
            put( "marginRatio", null );
            put( "liquidationPrice", null );
            put( "markPrice", null );
            put( "lastPrice", null );
            put( "collateral", null );
            put( "marginMode", null );
            put( "side", side );
            put( "percentage", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
            put( "hedged", null );
        }});
    }

