    /**
     * @method
     * @name defx#closePosition
     * @description closes an open position for a market
     * @see https://api-docs.defx.com/#b2c08074-c4d9-4e50-b637-0d6c498fa29e
     * @param {string} symbol unified CCXT market symbol
     * @param {string} [side] one-way mode: 'buy' or 'sell', hedge-mode: 'long' or 'short'
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.positionId] the position id you want to close
     * @param {string} [params.type] 'MARKET' or 'LIMIT'
     * @param {string} [params.quantity] how much of currency you want to trade in units of base currency
     * @param {string} [params.price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @returns {object} An [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> closePosition(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object side = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object positionId = this.safeString(parameters, "positionId");
            if (Helpers.isTrue(Helpers.isEqual(positionId, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " closePosition() requires a positionId")) ;
            }
            Object type = this.safeStringUpper(parameters, "type");
            if (Helpers.isTrue(Helpers.isEqual(type, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " closePosition() requires a type")) ;
            }
            Object quantity = this.safeString(parameters, "quantity");
            if (Helpers.isTrue(Helpers.isEqual(quantity, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " closePosition() requires a quantity")) ;
            }
            final Object finalPositionId = positionId;
            final Object finalType = type;
            final Object finalQuantity = quantity;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "positionId", finalPositionId );
                put( "type", finalType );
                put( "quantity", finalQuantity );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(type, "MARKET")))
            {
                Object price = this.safeString(parameters, "price");
                if (Helpers.isTrue(Helpers.isEqual(price, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " closePosition() requires a price")) ;
                }
                Helpers.addElementToObject(request, "price", price);
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("positionId", "type", "quantity", "price")));
            Object response = (this.v1PrivateDeleteApiPositionPositionId(this.extend(request, parameters))).join();
            //
            //     {}
            //
            return response;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

