    /**
     * @method
     * @name defx#fetchLedger
     * @description fetch the history of changes, actions done by the user or operations that altered the balance of the user
     * @see https://api-docs.defx.com/#38cc8974-794f-48c0-b959-db045a0ee565
     * @param {string} [code] unified currency code
     * @param {int} [since] timestamp in ms of the earliest ledger entry
     * @param {int} [limit] max number of ledger entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest ledger entry
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {object} a [ledger structure]{@link https://docs.ccxt.com/?id=ledger}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchLedger(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchLedger", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDynamic("fetchLedger", code, since, limit, parameters)).join();
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start", since);
            } else
            {
                Helpers.addElementToObject(request, "start", 0);
            }
            Object until = this.safeInteger(parameters, "until");
            if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                parameters = this.omit(parameters, "until");
                Helpers.addElementToObject(request, "end", until);
            } else
            {
                Helpers.addElementToObject(request, "end", this.milliseconds());
            }
            Object response = (this.v1PrivateGetApiWalletTransactions(this.extend(request, parameters))).join();
            Object data = this.safeList(response, "transactions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseLedger(data, null, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // {
        //     "id": "01JCSZS6H5VQND3GF5P98SJ29C",
        //     "timestamp": 1731744012054,
        //     "type": "FundingFee",
        //     "amount": "0.02189287",
        //     "asset": "USDC",
        //     "operation": "CREDIT"
        // }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object amount = this.safeString(item, "amount");
        Object currencyId = this.safeString(item, "asset");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object timestamp = this.safeInteger(item, "timestamp");
        Object type = this.safeString(item, "type");
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", Defx.this.safeString(item, "id") );
            put( "direction", null );
            put( "account", null );
            put( "referenceAccount", null );
            put( "referenceId", null );
            put( "type", Defx.this.parseLedgerEntryType(type) );
            put( "currency", code );
            put( "amount", Defx.this.parseNumber(amount) );
            put( "timestamp", timestamp );
            put( "datetime", Defx.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", null );
            put( "fee", null );
        }}, currency);
    }

